#include <stdio.h>
#include <string.h>

int main() {
    int T;
    char s[27], t[27];
    int k, i, j;

    scanf("%d", &T);
    while (T--) {
        scanf(" %s %d", s, &k);
        int n = strlen(s);
        int cnt[26] = {0};

        for (i = 0; i < n; i++)
            cnt[s[i] - 'a']++;

        for (i = 0; i < 26; i++)
            for (j = 0; j < cnt[i]; j++)
                printf("%c", 'a' + i);

        for (i = 0; i < k - n; i++)
            printf("a");

        printf("\n");
    }

    return 0;
}

