public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();

        while (T-- > 0) {
            String s = sc.nextLine();
            int k = sc.nextInt();
            sc.nextLine();
            int n = s.length();
            int cnt[] = new int[26];

            for (int i = 0; i < n; i++)
                cnt[s.charAt(i) - 'a']++;

            for (int i = 0; i < 26; i++)
                for (int j = 0; j < cnt[i]; j++)
                    System.out.print((char)('a' + i));

            for (int i = 0; i < k - n; i++)
                System.out.print('a');

            System.out.println();
        }

        sc.close();
    }
}

